var maxScoreSightseeingPair = function(values) {
    let bestLeft = values[0] + 0;
    let ans = -Infinity;
    for (let j = 1; j < values.length; j++) {
        ans = Math.max(ans, bestLeft + values[j] - j);
        bestLeft = Math.max(bestLeft, values[j] + j);
